class Solution {
public:
    int strangePrinter(string s) {
        if (s.empty()) return 0;
        vector<char> runs;
        char current = s[0];
        runs.push_back(current);
        for (int i = 1; i < s.size(); ++i) {
            if (s[i] != current) {
                current = s[i];
                runs.push_back(current);
            }
        }
        int count = runs.size();
        for (int i = 1; i < runs.size() - 1; ++i) {
            if (runs[i-1] == runs[i+1]) {
                count--;
            }
        }
        return count;
    }
};

